  'e6302232903a9f2fc6f7882b7c5ce521bf7d276bafddc0c33166612f4b443d38' => 'Lorsque l\'option de configuration est définie, nous en prenons en compte pour les appareils pour un certain sous-ensemble défini de règles de correspondance où l\'élément de configuration a été activé. Ces règles sont les suivantes:',
  'e7586475609a0481a4e66a3befa5b21f3a618b78ec8f5bc0791f1b23b60f96ef' => 'Afficher la découverte',
